import React from 'react';
import { Link, useLocation } from 'react-router-dom';

function Navbar() {
  const location = useLocation();
  const links = [
    { name: 'Authority', path: '/authority', icon: '👥' },
    { name: 'Bin', path: '/bin', icon: '🗂️' },
    { name: 'Driver', path: '/driver', icon: '🚗' },
    { name: 'User', path: '/user', icon: '👤' },
    { name: 'Vehicle', path: '/vehicle', icon: '🚛' }
  ];

      const navStyles = {
        background: 'rgba(255, 255, 255, 0.1)',
        backdropFilter: 'blur(20px)',
        padding: '15px 0',
        boxShadow: '0 8px 32px rgba(0, 0, 0, 0.1)',
        borderBottom: '1px solid rgba(255, 255, 255, 0.2)',
        position: 'sticky',
        top: 0,
        zIndex: 1000,
        transition: 'all 0.3s ease',
      };

  const containerStyles = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '0 20px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
  };

      const logoStyles = {
        fontSize: '1.6rem',
        fontWeight: '700',
        background: 'linear-gradient(135deg, #fff 0%, #f0f0f0 100%)',
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        textDecoration: 'none',
        display: 'flex',
        alignItems: 'center',
        gap: '10px',
        transition: 'all 0.3s ease',
      };

  const navLinksStyles = {
    display: 'flex',
    gap: '30px',
    alignItems: 'center',
  };

      const linkStyles = (isActive) => ({
        color: isActive ? '#ffffff' : 'rgba(255, 255, 255, 0.8)',
        textDecoration: 'none',
        padding: '10px 20px',
        borderRadius: '12px',
        fontWeight: '600',
        transition: 'all 0.3s ease',
        background: isActive ? 'rgba(255, 255, 255, 0.2)' : 'rgba(255, 255, 255, 0.05)',
        backdropFilter: 'blur(10px)',
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        fontSize: '0.95rem',
        border: isActive ? '1px solid rgba(255, 255, 255, 0.3)' : '1px solid rgba(255, 255, 255, 0.1)',
        boxShadow: isActive ? '0 4px 15px rgba(255, 255, 255, 0.2)' : 'none',
      });

      const homeLinkStyles = (isActive) => ({
        ...linkStyles(isActive),
        background: isActive ? 'rgba(255, 255, 255, 0.3)' : 'rgba(255, 255, 255, 0.15)',
        color: 'white',
        fontWeight: '700',
        fontSize: '1rem',
      });

  return (
    <nav style={navStyles}>
      <div style={containerStyles}>
        <Link to="/" style={homeLinkStyles(location.pathname === '/')}>
          🏠 Home
        </Link>

        <div style={navLinksStyles}>
          {links.map(link => (
            <Link 
              key={link.name} 
              to={link.path} 
              style={linkStyles(location.pathname === link.path)}
            >
              <span>{link.icon}</span>
              {link.name}
            </Link>
          ))}
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
